var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모네~!","JPN":"モネ！","ENG":"Mone!","TWN":"莫妮～！"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모오네!","JPN":"モオネ！","ENG":"Moone!","TWN":"莫妮！"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":null,"R":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SERINA_COFFIN_SUMMER_NULL","text":{"KOREA":"다음에도 잘 부탁해요, 손님 여러분~","JPN":"またよろしくお願いします、お客様！","ENG":"Thanks guys, come again!","TWN":"歡迎再次光臨喔～"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"XIEN_FREEDOM_SUMMER_NULL","text":{"KOREA":"드……. 드디어 매진이군……. 대체 재고를 얼마나 싸들고 온 거야…….","JPN":"つ……ついに売り切れたか……一体在庫をどれだけ持ってきたんだ……","ENG":"F-finally, we sold everything... Why did you have to bring so many?","TWN":"終…終於全部賣光光了……你到底是打包多少東西過來啊……"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"흐아, 저도 힘이 쭉 빠져 버렸네요.","JPN":"ふう、私も全身の力が抜けてしまいました。","ENG":"Phew, I’m so exhausted.","TWN":"呼～超累的！"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"이 상태로는 배달 다닐 엄두도 못 내겠어요.","JPN":"この状態では配達する気力もありません。","ENG":"I don’t think I’ll be able to deliver anything today.","TWN":"累到我完全不想動了。"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"SERINA_COFFIN_SUMMER_NULL","text":{"KOREA":"와아~♪ 저 아르바이트 하면서 전량 매진은 처음이에요!","JPN":"わあ～♪　このバイトで全部売り切れたのは初めてです！","ENG":"Wow! ♪ This is the first time I’ve seen an item sold out since I started working here!","TWN":"哇～♪這是我的打工人生中，第一次把東西賣光欸！"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SERINA_COFFIN_SUMMER_NULL","text":{"KOREA":"눈코 뜰 새 없이 바쁘긴 했지만…… 정말 뿌듯하네요.","JPN":"目が回るほど忙しかったけど…… 本当に嬉しいですね。","ENG":"It was a very busy day... but it feels great!","TWN":"雖然忙得不可開交……但心卻很滿足呢！"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"XIEN_FREEDOM_SUMMER_NULL","text":{"KOREA":"훗훗. 이걸로 친구들의 빚은 갚은 셈이 되겠군.","JPN":"ふっふっ。これで友の借りは返したな。","ENG":"Heh heh, it looks like I’ve finally settled my friends’ debt.","TWN":"呵呵，這就算是還朋友的人情囉！"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"앗, 어떤 기분인지 이해해요!","JPN":"あっ、私もどんな気持ちなのかわかります！","ENG":"Oh, I know that feeling!","TWN":"我明白你的心情！"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"저도 배달 다닐 때 고객님들의 미소를 보면 힘이 나거든요.","JPN":"配達する時、お客様の笑顔を見ると力が湧くんです。","ENG":"Smiles on my clients’ faces give me the energy to go on, you know!","TWN":"我送貨的時候，客人的笑容就是我動力的來源。"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"그게 바로 일하면서 느끼는 성취감이죠!","JPN":"それがまさに、働きながら感じる達成感です！","ENG":"That’s called a sense of accomplishment!","TWN":"那就是工作中的成就感！"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"SERINA_COFFIN_SUMMER_NULL","text":{"KOREA":"이게 바로, 성취감…….","JPN":"これが、達成感……","ENG":"A sense of accomplishment, huh?","TWN":"這個就是，成就感…"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"XIEN_FREEDOM_SUMMER_NULL","text":{"KOREA":"호오, 정처없이 떠도는 나한테는 생소한 감정이군.","JPN":"ほう、あてもなくさすらう私にはあまりない感情だな。","ENG":"That’s an unfamiliar feeling that I’ve never had as a wanderer.","TWN":"喔呵，對居無定所的我來說，這感覺很陌生呢！"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"XIEN_FREEDOM_SUMMER_NULL","text":{"KOREA":"하지만 얘기를 들어 보니 어떤 기분일지 알 것 같아.","JPN":"だが今の話で、どんな気持ちかわかった気もする。","ENG":"But I think I know what it is like.","TWN":"不過聽完好像覺得有點明白。"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"XIEN_FREEDOM_SUMMER_NULL","text":{"KOREA":"나도 끈끈한 우정으로 맺어진 친구들을 위해 희생할 때 전율이 흐르거든.","JPN":"私も固い友情で結ばれた友のために身を投じる時、戦慄が走るのだ。","ENG":"I feel so thrilled when I sacrifice myself for my dearest friends.","TWN":"我爲生死之交的朋友犧牲時，也會有全身戰慄的感覺。"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"XIEN_FREEDOM_SUMMER_NULL","text":{"KOREA":"캬아, 나 이렇게 멋져도 되는 거야?","JPN":"くふふ、私ってばこんなにカッコよくてもいいのか？","ENG":"Man, how can I be so cool?","TWN":"哎呀！我這麼帥沒問題嗎？"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};